xan from data/agora_repertoire_opendata.json.gz --root publications | xan select denomination,exercices | xan explode exercices -S -e '_.parse_json()' | xan explode exercice -e '_.parse_json().publicationCourante.activites || {}' | xan map 'exercice.parse_json().publicationCourante | [_.objet.try(), _.publicationDate.datetime("%d/%m/%Y à %H:%M:%S").try(), _.domainesIntervention.join("§").try(), _.actionsRepresentationInteret[0].tiers.join("§").try(), _.actionsRepresentationInteret[0].reponsablesPublics.join("§").try(), _.actionsRepresentationInteret[0].decisionsConcernees.join("§").try(), _.actionsRepresentationInteret[0].actionsMenees.join("§").try()] as (objet, date, domaines, tiers, responsables, decisions, actions)' | xan search -s objet -N | xan drop exercice

xan from data/agora_repertoire_opendata.json.gz --root publications | xan select denomination,exercices,codePostal,activites.listNiveauIntervention | xan explode exercices -S -e '_.parse_json()' | xan map 'exercice.parse_json().publicationCourante | [_.nombreSalaries, _.montantDepense, _.activites.len(), (_.activites || []).map(x => (x.publicationCourante.domainesIntervention.try() || []).join("%")).join("%")] as (salaries, amount, activites, domaines)' | xan drop exercice | xan filter 'salaries && amount && activites > 0' | xan separate -krc amount --into lower_bound '(?:et )?< ([\d\s]+)' | xan transform lower_bound '_.replace(" ", "")'
